body:
After enjoying instantsearch and taking much of your time with my questions, i'm finally happy to be able to contribute a bit with this dateRange widget based on the uikit(www.getuikit.com) framework.
Note: the moment.js library is required

Using :

``` javascript
search.addWidget(
   instantsearch.widgets.dateRange({
        container: '#facet-acdsp_approved_date',
        attributeName: 'acdsp_approved_date',
        label: 'Civil Defense Shelter Plan Date',
        dateFormat: "DD/MM/YYYY",
        dateRangeOptions: {},
      }),
)
```

Widget Code

``` javascript
instantsearch.widgets.dateRange = function dateRange(options) {

    if (!options.attributeName || !options.container) {
        throw new Error('dateRange: usage: dateRange({container, attributeName, dateRangeOptions})');
    }
    var $container = $(options.container);
    if ($container.length === 0) {
        throw new Error('dateRange: cannot select \'' + options.container + '\'');
    }
    var attributeName = options.attributeName;
    var lowerBoundAttributeName = options.attributeName.lowerBound || options.attributeName;
    var upperBoundAttributeName = options.attributeName.upperBound || options.attributeName;
    var dateFormat = options.dateFormat || "DD/MM/YYYY";
    var dateRangeOptions = options.dateRangeOptions || {};
    var data = {};

    return {
        getConfiguration: function (currentSearchParams) {
        },
        init: function (args) {
            var helper = args.helper;
            var from, to;

            var html = '<div class="facet-date-range root">';
            html += '<div class="facet-title">'
            html += '<h5>' + (options.label ? options.label : 'Date range') + '</h5>';
            html += '</div>';
            html += '<div class="facet-body">';
            html += '<form class="uk-form uk-clearfix"><div class="uk-form-icon"><i class="uk-icon-calendar"></i><input type="text" name="from" placeholder="From" data-uk-datepicker="{format:\''+ dateFormat+'\'}" class="uk-width-1-2"></div><div class="uk-form-icon"><i class="uk-icon-calendar"></i><input type="text" name="to" placeholder="To" class="uk-width-1-2" data-uk-datepicker="{format:\''+ dateFormat+'\'}" ></div></form>';
            html += '</div>';
            html += '</div>';

            $container.html( html );

            // if javascript is required to instantiate the datepicker
            // var datepicker = UIkit.datepicker('.uk-datepicker', {
            //     mobile: true,
            //     weekstart: 1,
            //     format:'DD/MM/YYYY',
            //     offsettop: 5,
            //     minDate: false,
            //     maxDate: false,
            //     pos: 'auto'
            //  });

            $container.on('change', function(event) {
                var target = $(event.target),
                    element = $(this);

                if ( target.is( 'input[name="from"]' ) ) {
                    data.from  = target.val() ? moment(target.val(), dateFormat).unix() : 0;
                } else if ( target.is( 'input[name="to"]' ) ) {
                    data.to  = target.val() ? moment(target.val(), dateFormat).unix() : Number.MAX_SAFE_INTEGER;
                }

                from = helper.state.getNumericRefinement(lowerBoundAttributeName, '>=');
                from = from && from[0];

                to = helper.state.getNumericRefinement(upperBoundAttributeName, '<=');
                to = to && to[0];

                if (data.from !== from) {
                    helper.removeNumericRefinement(lowerBoundAttributeName, '>=');
                    helper.addNumericRefinement(lowerBoundAttributeName, '>=', data.from);
                    helper.search();
                }

                if (data.to !== to) {
                    helper.removeNumericRefinement(upperBoundAttributeName, '<=');
                    helper.addNumericRefinement(upperBoundAttributeName, '<=', data.to);
                    helper.search();
                }

            });

        },
        render: function (args) {
        }
    }
}
```
